# Audit des mécanismes de persistance dans le registre

function Audit-Persistance {
    Write-Host "=== Audit persistance registre ==="

    # ─── Run Keys (démarrage automatique) ───
    $runKeys = @(
        'HKLM:\Software\Microsoft\Windows\CurrentVersion\Run',
        'HKLM:\Software\Microsoft\Windows\CurrentVersion\RunOnce',
        'HKCU:\Software\Microsoft\Windows\CurrentVersion\Run',
        'HKCU:\Software\Microsoft\Windows\CurrentVersion\RunOnce'
    )

    Write-Host "`n[Run Keys]"
    foreach ($key in $runKeys) {
        try {
            $values = Get-ItemProperty $key -ErrorAction Stop
            $values.PSObject.Properties | Where-Object { $_.Name -notlike 'PS*' } | ForEach-Object {
                Write-Host "  [$key]"
                Write-Host "    $($_.Name) = $($_.Value)"
                # Flags suspects
                if ($_.Value -match 'powershell|cmd|wscript|mshta|regsvr32') {
                    Write-Host "    [SUSPECT] Exécutable connu LOLBin"
                }
            }
        } catch { }
    }

    # ─── Services Windows (mécanisme de persistance courant) ───
    Write-Host "`n[Services récents]"
    Get-WinEvent -FilterHashtable @{LogName='System'; Id=7045; StartTime=(Get-Date).AddDays(-30)} `
        -ErrorAction SilentlyContinue | ForEach-Object {
        Write-Host "  $($_.TimeCreated) : $($_.Message.Substring(0,[Math]::Min(150,$_.Message.Length)))"
    }
}

Audit-Persistance
