# Analyse des processus en mémoire — techniques LOLBins et injections

function Analyze-ProcessesSuspects {
    Write-Host "=== Analyse processus suspects ==="

    # Processus PowerShell encodés
    Write-Host "`n[PowerShell avec encoding]"
    Get-Process powershell, pwsh -ErrorAction SilentlyContinue | ForEach-Object {
        try {
            $cmdLine = (Get-WmiObject Win32_Process -Filter "ProcessId=$($_.Id)").CommandLine
            if ($cmdLine -match '-enc|-EncodedCommand|-e ') {
                Write-Host "  [SUSPECT] PID $($_.Id) : $cmdLine"
            } else {
                Write-Host "  PID $($_.Id) : $($cmdLine.Substring(0,[Math]::Min(100,$cmdLine.Length)))"
            }
        } catch { }
    }

    # Processus sans signature numérique
    Write-Host "`n[Processus non signés dans System32]"
    Get-Process | Where-Object { $_.Path -like '*System32*' } | ForEach-Object {
        $sig = Get-AuthenticodeSignature $_.Path -ErrorAction SilentlyContinue
        if ($sig -and $sig.Status -ne 'Valid') {
            Write-Host "  [NON SIGNÉ] $($_.Name) ($($_.Path))"
        }
    }

    # Processus parents-enfants suspects
    Write-Host "`n[Parents suspects]"
    $parentsSuspects = @('winword.exe', 'excel.exe', 'outlook.exe', 'chrome.exe', 'firefox.exe')
    Get-WmiObject Win32_Process | ForEach-Object {
        $parentPID = $_.ParentProcessId
        $parent = Get-Process -Id $parentPID -ErrorAction SilentlyContinue
        if ($parent -and ($parentsSuspects -contains $parent.Name.ToLower())) {
            if ($_.Name -match 'cmd|powershell|wscript') {
                Write-Host "  [INJECTION] $($parent.Name) → $($_.Name) (PID $($_.ProcessId))"
            }
        }
    }
}

Analyze-ProcessesSuspects
