```powershell
# Génération d'une timeline forensics Windows

function New-TimelineForensics {
    param(
        [int]$DerniersJours = 1,
        [string]$Sortie = "$env:TEMP\timeline_$(Get-Date -Format 'yyyyMMdd_HHmmss').csv"
    )

    $timeline = [System.Collections.Generic.List[PSObject]]::new()
    $debut = (Get-Date).AddDays(-$DerniersJours)

    # Événements Security clés
    $idsImportants = @(4624, 4625, 4720, 4732, 4688, 4698, 1102)

    Get-WinEvent -FilterHashtable @{
        LogName   = 'Security'
        Id        = $idsImportants
        StartTime = $debut
    } -ErrorAction SilentlyContinue | ForEach-Object {
        $timeline.Add([PSCustomObject]@{
            Timestamp = $_.TimeCreated
            Source    = 'Security'
            EventID   = $_.Id
            Resume    = $_.Message.Substring(0, [Math]::Min(120, $_.Message.Length))
        })
    }

    # Fichiers Prefetch récents
    Get-ChildItem 'C:\Windows\Prefetch\*.pf' -ErrorAction SilentlyContinue |
        Where-Object { $_.LastWriteTime -gt $debut } | ForEach-Object {
        $timeline.Add([PSCustomObject]@{
            Timestamp = $_.LastWriteTime
            Source    = 'Prefetch'
            EventID   = 0
            Resume    = "Exécuté : $($_.BaseName -replace '-[A-F0-9]+$','')"
        })
    }

    $triée = $timeline | Sort-Object Timestamp
    $triée | Export-Csv $Sortie -NoTypeInformation -Encoding UTF8

    Write-Host "Timeline créée : $Sortie ($($timeline.Count) événements)"
    $triée | Select-Object -Last 10 | Format-Table -AutoSize
}

New-TimelineForensics -DerniersJours 1
